 1	import React, { FC } from 'react';
 2	
 3	import { VirtualMachineInstanceModelGroupVersionKind } from '@kubevirt-ui/kubevirt-api/console';
 4	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import Consoles from '@kubevirt-utils/components/Consoles/Consoles';
 6	import Loading from '@kubevirt-utils/components/Loading/Loading';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 9	import {
10	  Bullseye,
11	  EmptyState,
12	  EmptyStateBody,
13	  PageSection,
14	  PageSectionVariants,
15	} from '@patternfly/react-core';
16	import { NavPageComponentProps } from '@virtualmachines/details/utils/types';
17	
18	import { printableVMStatus } from '../../../utils';
19	
20	import './VirtualMachineConsolePage.scss';
21	
22	const VirtualMachineConsolePage: FC<NavPageComponentProps> = ({ obj: vm }) => {
23	  const { t } = useKubevirtTranslation();
24	  const [vmi, vmiLoaded] = useK8sWatchResource<V1VirtualMachineInstance>({
25	    groupVersionKind: VirtualMachineInstanceModelGroupVersionKind,
26	    isList: false,
27	    name: vm?.metadata?.name,
28	    namespace: vm?.metadata?.namespace,
29	  });
30	
31	  if (!vmi || vm?.status?.printableStatus === printableVMStatus.Stopped) {
32	    return (
33	      <EmptyState>
34	        <EmptyStateBody>
35	          {t('This VirtualMachine is down. Please start it to access its console.')}
36	        </EmptyStateBody>
37	      </EmptyState>
38	    );
39	  }
40	
41	  if (!vmiLoaded) {
42	    return (
43	      <Bullseye>
44	        <Loading />
45	      </Bullseye>
46	    );
47	  }
48	
49	  return (
50	    <PageSection
51	      className="VirtualMachineConsolePage-page-section"
52	      variant={PageSectionVariants.light}
53	    >
54	      <Consoles consoleContainerClass="virtual-machine-console-page" vmi={vmi} />
55	    </PageSection>
56	  );
57	};
58	
59	export default VirtualMachineConsolePage;

